// Orquesta: Geocoding -> buildingInsights -> dataLayers -> Claude fallback
// Env: GOOGLE_API_KEY (req), ANTHROPIC_API_KEY (fallback)
// Input body: { address?, lat?, lon? }

const src = $input.first().json;
const body = src.body || src;
const inAddress = (body.address || '').toString().trim();
let lat = body.lat != null ? Number(body.lat) : null;
let lon = body.lon != null ? Number(body.lon) : null;
if (!inAddress && (lat == null || lon == null)) {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'address o lat/lon requeridos' } }];
}

// Acceso a env vars tolerante: el task runner de n8n puede denegar acceso ($env getter
// arroja TypeError cuando no está permitido). Devolvemos null en lugar de crashear.
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GKEY = safeEnv('GOOGLE_API_KEY');
const AKEY = safeEnv('ANTHROPIC_API_KEY');
// Genera URLs de Google Static Maps con un círculo opcional que indica
// el área analizada por Google Solar (proporcional a sqrt(areaM2/π)).
function buildStaticMapUrls(lat, lon, areaM2) {
  if (lat == null || lon == null) return { satellite: null, road: null, satelliteHD: null };
  const enc = encodeURIComponent;
  // Genera un círculo aproximado de radio r metros como path codificado.
  // 24 puntos alrededor del centro. Cada offset en lat/lon se calcula con la fórmula
  // de aproximación local: dLat = r/R; dLon = r/(R*cos(lat)). R = 6378137 m.
  const buildCirclePath = (r) => {
    if (!r || r <= 0) return null;
    const N = 24;
    const R = 6378137;
    const cosLat = Math.cos(lat * Math.PI / 180);
    const pts = [];
    for (let i = 0; i <= N; i++) {
      const t = (i / N) * 2 * Math.PI;
      const dLat = (r * Math.cos(t)) / R * (180 / Math.PI);
      const dLon = (r * Math.sin(t)) / (R * cosLat) * (180 / Math.PI);
      pts.push((lat + dLat).toFixed(6) + ',' + (lon + dLon).toFixed(6));
    }
    return 'color:0xFF8C00FF|fillcolor:0xFF8C0033|weight:3|' + pts.join('|');
  };
  const radiusM = areaM2 && areaM2 > 0 ? Math.sqrt(areaM2 / Math.PI) : null;
  const circlePath = radiusM ? buildCirclePath(radiusM) : null;
  const mk = (zoom, maptype, size, withCircle) => {
    const center = enc(lat + ',' + lon);
    const markers = enc('color:0xFF8C00|size:mid|' + lat + ',' + lon);
    let qs = 'center=' + center +
             '&zoom=' + zoom +
             '&size=' + size +
             '&maptype=' + maptype +
             '&markers=' + markers +
             '&scale=2' +
             '&key=' + enc(GKEY);
    if (withCircle && circlePath) qs += '&path=' + enc(circlePath);
    return 'https://maps.googleapis.com/maps/api/staticmap?' + qs;
  };
  return {
    satellite:   mk(20, 'satellite', '640x400', true),
    road:        mk(16, 'roadmap',   '640x400', false),
    // Versión HD (640x640 al doble de scale) para el lightbox.
    satelliteHD: mk(20, 'satellite', '640x640', true),
  };
}

if (!GKEY) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no accesible desde el Code node. En Railway, definir GOOGLE_API_KEY en el servicio n8n y permitir acceso del task runner (NODE_FUNCTION_ALLOW_EXTERNAL / N8N_RUNNERS_TASK_RUNNER_ALLOWED_ENV).', address: inAddress, lat, lon } }];
}

// 1) Geocoding si no hay coords. Validación estricta + manejo de status Google.
//    NUNCA throws — siempre devuelve {ok:false, reason} para que el respond node lo
//    propague como JSON limpio en lugar de "Respuesta inválida" / 500.
//    Normaliza abreviaturas colombianas (Cra, Cl, Av, Tv, Dg, ª/º) antes de consultar.
let resolvedAddress = inAddress;

// Normaliza una dirección colombiana para Google Geocoding: expande abreviaturas comunes,
// quita ordinales (24ª → 24a), añade ", Colombia" si la dirección no menciona el país.
function normalizeColombianAddress(s) {
  if (!s) return s;
  let t = String(s).trim();
  // Indicadores ordinales: 24ª-44 → 24a-44; 12º → 12. Google los confunde con caracteres raros.
  t = t.replace(/[ªº°]/g, 'a').replace(/(\d)\s*a\b/gi, '$1a');
  // Abreviaturas: aplicar SOLO con word-boundary y respetando case-insensitive.
  // Reemplazos en orden de longitud descendente para evitar colisiones (Crr antes de Cr).
  const repl = [
    [/\b(carr?era|krr|crr|cra|cr)\.?\b/gi, 'Carrera'],
    [/\b(calle|cll|cl)\.?\b/gi,            'Calle'],
    [/\b(avenida|avda|avd|av)\.?\b/gi,    'Avenida'],
    [/\b(transversal|trv|tv)\.?\b/gi,     'Transversal'],
    [/\b(diagonal|dgn|dg)\.?\b/gi,         'Diagonal'],
    [/\b(autopista|aut|atp)\.?\b/gi,      'Autopista'],
    [/\b(manzana|mzn|mz)\.?\b/gi,          'Manzana'],
    [/\b(apartamento|apto|apt)\.?\b/gi,   'Apartamento'],
    [/\b(barrio|brr|bo)\.?\b/gi,           'Barrio'],
  ];
  for (const [re, val] of repl) t = t.replace(re, val);
  // Colapsar espacios.
  t = t.replace(/\s+/g, ' ').trim();
  // Asegurar país: si no menciona Colombia, añadir.
  if (!/colombia/i.test(t)) t = t + ', Colombia';
  return t;
}

async function geocodeOnce(query) {
  return this.helpers.httpRequest({
    method: 'GET',
    url: 'https://maps.googleapis.com/maps/api/geocode/json',
    qs: { address: query, key: GKEY, region: 'co', language: 'es' },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
}
const geocode = geocodeOnce.bind(this);

if (lat == null || lon == null) {
  // Heurística mínima: rechazar inputs imposibles de geocodificar (ej: "cra" sin número).
  if (inAddress.length < 8) {
    return [{ json: { ok: false, reason: 'invalid_input',
      detail: 'Ingresa una dirección más completa (calle/carrera + número + ciudad o departamento). Ej: "Carrera 7 # 32-16, Bogotá".',
      address: inAddress, lat: null, lon: null } }];
  }

  // Generar variantes a probar: normalizada → original → solo ciudad detectada.
  const normalized = normalizeColombianAddress(inAddress);
  const variants = [];
  if (normalized !== inAddress) variants.push(normalized);
  variants.push(inAddress);
  // Fallback ciudad: si el input contiene una ciudad reconocible al final, geocodificar solo eso.
  // Heurística: última palabra >3 chars sin números, asumiendo formato "<vía> <num> <ciudad>".
  const cityMatch = inAddress.match(/[A-Za-záéíóúñ]{4,}\s*$/i);
  if (cityMatch) {
    const cityOnly = cityMatch[0].trim() + ', Colombia';
    if (!variants.includes(cityOnly)) variants.push(cityOnly);
  }

  let geoResp = null;
  let geo = null;
  let usedQuery = null;
  for (const q of variants) {
    try {
      geoResp = await geocode(q);
    } catch (e) {
      return [{ json: { ok: false, reason: 'geocode_network',
        detail: 'No se pudo contactar Google Geocoding: ' + (e?.message || 'error desconocido'),
        address: inAddress, lat: null, lon: null } }];
    }
    if (geoResp.statusCode === 200 && geoResp.body && geoResp.body.status === 'OK' &&
        Array.isArray(geoResp.body.results) && geoResp.body.results.length > 0) {
      geo = geoResp.body;
      usedQuery = q;
      break;
    }
  }
  // Si ninguna variante respondió OK, devolver error específico según el último intento.
  if (!geo) {
    const last = geoResp || {};
    const body = last.body || {};
    // Modo degradado: si Geocoding falla pero tenemos Claude, dejar que estime
    // sin coords precisas. El usuario obtiene un baseline mientras arregla la key.
    const geocodeFailDetail = (() => {
      if (last.statusCode && last.statusCode !== 200) return 'Google Geocoding HTTP ' + last.statusCode;
      if (body.status === 'ZERO_RESULTS') return 'Dirección no encontrada (probadas ' + variants.length + ' variantes).';
      if (body.status === 'REQUEST_DENIED') return 'Geocoding rechazado: ' + (body.error_message || 'la API key tiene restricciones que no permiten uso server-side. Crear nueva key con Application restrictions = None o IP addresses, y actualizar GOOGLE_API_KEY en Railway.');
      if (body.status && body.status !== 'OK') return 'Geocoding status ' + body.status + ': ' + (body.error_message || '');
      return 'Geocoding falló sin detalle';
    })();
    const geocodeFailReason = (() => {
      if (last.statusCode && last.statusCode !== 200) return 'geocode_http_' + last.statusCode;
      if (body.status === 'ZERO_RESULTS') return 'no_geocode';
      if (body.status) return 'geocode_' + body.status.toLowerCase();
      return 'no_geocode';
    })();

    if (!AKEY) {
      // Sin Claude no podemos degradar — devolver error claro.
      return [{ json: { ok: false, reason: geocodeFailReason,
        detail: geocodeFailDetail + ' · ANTHROPIC_API_KEY no configurada para fallback.',
        address: inAddress, attempted: variants, lat: null, lon: null } }];
    }
    // Claude estimará con el address text. Marcamos el origen para que la UI sepa
    // que es estimación y la causa raíz para diagnóstico.
    resolvedAddress = inAddress;
    // lat/lon quedan null — la app puede mostrar una bandera "sin geolocalización".
    // Saltar al bloque Claude fallback; setear flag para que skip los pasos Solar API.
    var skipSolar = true;
    var degradedReason = geocodeFailReason;
    var degradedDetail = geocodeFailDetail;
  } else {
    var skipSolar = false;
  }
  const top = geo.results[0];
  lat = top?.geometry?.location?.lat;
  lon = top?.geometry?.location?.lng;
  if (typeof lat !== 'number' || typeof lon !== 'number') {
    return [{ json: { ok: false, reason: 'geocode_no_coords',
      detail: 'Google Geocoding respondió pero sin coordenadas válidas.',
      address: inAddress, lat: null, lon: null } }];
  }
  resolvedAddress = top.formatted_address || usedQuery || inAddress;
}

// 2) Google Solar buildingInsights — cascada HIGH → MEDIUM → LOW.
//    HIGH es la mejor (~30cm/pixel DSM) cuando está disponible. Solo fallback si 404.
let solar = null;
let effectiveQuality = null;  // 'HIGH' | 'MEDIUM' | 'LOW' — calidad EFECTIVA usada
if (!skipSolar) {
  const qualities = ['HIGH', 'MEDIUM', 'LOW'];
  for (const q of qualities) {
    try {
      const sr = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://solar.googleapis.com/v1/buildingInsights:findClosest',
        qs: { 'location.latitude': lat, 'location.longitude': lon, requiredQuality: q, key: GKEY },
        json: true,
        returnFullResponse: true,
        ignoreHttpStatusErrors: true,
      });
      if (sr.statusCode === 200 && sr.body) {
        solar = sr.body;
        effectiveQuality = q;
        break;
      }
      // 404 = sin cobertura para esa calidad, intentar la siguiente.
      // Otros errores (403, 429): salir del loop.
      if (sr.statusCode !== 404) break;
    } catch (_) { break; }
  }
}

// 3) Google Solar dataLayers — usa la calidad efectiva del paso 2 (o LOW si paso 2 falló).
let imagery = null;
if (!skipSolar) {
  const dlQuality = effectiveQuality || 'LOW';
  // Helper local: GeoTIFF URLs vienen sin key — Google requiere autenticación al descargar.
  const withKey = (u) => (typeof u === 'string' && u) ? (u + (u.includes('?') ? '&' : '?') + 'key=' + GKEY) : u;
  try {
    const dl = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://solar.googleapis.com/v1/dataLayers:get',
      qs: {
        'location.latitude': lat,
        'location.longitude': lon,
        radiusMeters: 50,
        view: 'FULL_LAYERS',
        requiredQuality: dlQuality,
        key: GKEY,
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    if (dl.statusCode === 200 && dl.body) {
      const d = dl.body;
      imagery = {
        dsmUrl: withKey(d.dsmUrl) || null,
        rgbUrl: withKey(d.rgbUrl) || null,
        maskUrl: withKey(d.maskUrl) || null,
        annualFluxUrl: withKey(d.annualFluxUrl) || null,
        monthlyFluxUrl: withKey(d.monthlyFluxUrl) || null,
        hourlyShadeUrls: Array.isArray(d.hourlyShadeUrls) ? d.hourlyShadeUrls.map(withKey) : [],
        imageryDate: d.imageryDate || null,
        imageryQuality: d.imageryQuality || null,
      };
    }
  } catch {}
}

const sp = solar && solar.solarPotential;
if (sp) {
  const areaM2 = sp.maxArrayAreaMeters2 != null ? Number(sp.maxArrayAreaMeters2) : null;
  // wholeRoofStats: el techo COMPLETO incluyendo zonas no aprovechables. Útil para
  // explicar al cliente la diferencia entre "techo total" y "aprovechable para paneles".
  const wholeRoofAreaM2 = sp.wholeRoofStats?.areaMeters2 != null ? Number(sp.wholeRoofStats.areaMeters2) : null;
  // groundAreaMeters2: footprint del edificio (área proyectada al suelo, sin pendiente).
  const groundAreaM2 = sp.groundAreaMeters2 != null ? Number(sp.groundAreaMeters2) : null;
  const maxPanels = sp.maxArrayPanelsCount != null ? Number(sp.maxArrayPanelsCount) : null;
  const sunshine = sp.maxSunshineHoursPerYear != null ? Number(sp.maxSunshineHoursPerYear) : null;
  let tiltDeg = null, azimuthDeg = null;
  const configs = sp.solarPanelConfigs || [];
  const best = configs.reduce((a, b) => (b.panelsCount > (a?.panelsCount || 0) ? b : a), null);
  // bestEnergyCfg: configuración que MAXIMIZA energía anual (no necesariamente paneles).
  // Útil cuando segmentos sombreados rinden menos: Google sugiere config "óptima" diferente.
  const bestEnergyCfg = configs.reduce((a, b) => (Number(b.yearlyEnergyDcKwh || 0) > Number(a?.yearlyEnergyDcKwh || 0) ? b : a), null);
  const panels = sp.solarPanels || [];
  if (panels.length) {
    tiltDeg = panels[0].orientation === 'LANDSCAPE' ? 10 : 15;
  }
  const roofSegs = sp.roofSegmentStats || [];
  if (roofSegs.length) {
    let sumArea = 0, sumAz = 0, sumPitch = 0;
    for (const s of roofSegs) {
      const a = s.stats?.areaMeters2 || 0;
      sumArea += a; sumAz += (s.azimuthDegrees || 0) * a; sumPitch += (s.pitchDegrees || 0) * a;
    }
    if (sumArea > 0) {
      azimuthDeg = Math.round(sumAz / sumArea);
      tiltDeg = Math.round(sumPitch / sumArea);
    }
  }

  // Shade index: ratio avg(top-N panels) / max(panel energy)
  // 1.0 = no shade; 0.8 = 20% effective shading
  let shadeIndex = null, shadeSource = null;
  const energies = panels.map(p => Number(p.yearlyEnergyDcKwh || 0)).filter(v => v > 0);
  if (energies.length && best?.panelsCount) {
    const sorted = [...energies].sort((a, b) => b - a);
    const topN = sorted.slice(0, Math.min(best.panelsCount, sorted.length));
    const avgTop = topN.reduce((s, v) => s + v, 0) / topN.length;
    const maxE = sorted[0];
    if (maxE > 0) {
      shadeIndex = Math.max(0.1, Math.min(1, avgTop / maxE));
      shadeSource = 'google-solar-panels';
    }
  }

  const roofSegments = roofSegs.map(s => ({
    azimuthDegrees: s.azimuthDegrees,
    pitchDegrees: s.pitchDegrees,
    areaMeters2: s.stats?.areaMeters2 || 0,
    groundAreaMeters2: s.groundAreaMeters2 || null,
    sunshineHoursPerYear: s.stats?.sunshineQuantiles ? s.stats.sunshineQuantiles[4] : null,
    // Coordenadas geográficas — permiten dibujar polígonos sobre el mapa Google Maps JS
    // y poner labels con el área. Si Google no las devuelve (raro), null y el frontend
    // omite el overlay para ese segmento.
    center: s.center ? { lat: Number(s.center.latitude), lng: Number(s.center.longitude) } : null,
    boundingBox: s.boundingBox && s.boundingBox.sw && s.boundingBox.ne ? {
      sw: { lat: Number(s.boundingBox.sw.latitude), lng: Number(s.boundingBox.sw.longitude) },
      ne: { lat: Number(s.boundingBox.ne.latitude), lng: Number(s.boundingBox.ne.longitude) },
    } : null,
  }));

  // FASE 2 GOOGLE SOLAR: solarPanels[] — cada panel individual con sus coords
  // exactas según el algoritmo de packing de Google. Permite renderizar el grid
  // de paneles azules estilo Google Solar Platform en el frontend.
  const solarPanels = panels.map(p => ({
    center: p.center ? { lat: Number(p.center.latitude), lng: Number(p.center.longitude) } : null,
    orientation: p.orientation || 'LANDSCAPE',
    yearlyEnergyDcKwh: p.yearlyEnergyDcKwh != null ? Number(p.yearlyEnergyDcKwh) : null,
    segmentIndex: p.segmentIndex != null ? Number(p.segmentIndex) : null,
  }));
  const panelHeightMeters = sp.panelHeightMeters != null ? Number(sp.panelHeightMeters) : 1.65;
  const panelWidthMeters = sp.panelWidthMeters != null ? Number(sp.panelWidthMeters) : 0.99;

  // Confidence basada en 4 señales (Opciones B+C+D combinadas):
  //   (a) qualityBase: resolución imagery Google Solar
  //   (b) completeness: completitud datos (paneles, sombra, segmentos, footprint)
  //   (c) pinPrecision: cuántos paneles individuales detectó Google (proxy precisión coords)
  //   (d) coherence: consistencia interna (tilt residencial + azimuth Sur ±60° + datos completos)
  // Cap LOW@0.92: aunque todo lo demás esté perfecto, imagery 1m/px tiene ±20% de error
  // inherente en el cálculo de área. Solo HIGH/MEDIUM pueden alcanzar 0.99.
  let qualityBase = 0.78;
  if (effectiveQuality === 'HIGH') qualityBase = 0.95;
  else if (effectiveQuality === 'MEDIUM') qualityBase = 0.88;
  else if (effectiveQuality === 'LOW') qualityBase = 0.82; // bumped from 0.78 (imagery LOW + buenos datos sigue siendo razonable)
  // (b) Completeness — máx +0.08
  const hasRealPanels = panels.length > 0;
  const shadeFromPanels = shadeSource === 'google-solar-panels';
  const hasImagery = !!(imagery && imagery.rgbUrl);
  const hasFullFootprint = (wholeRoofAreaM2 || 0) > 0;
  const hasMultipleSegments = Array.isArray(roofSegments) && roofSegments.length >= 2;
  const completeness =
    (hasRealPanels ? 0.02 : 0) +
    (shadeFromPanels ? 0.02 : 0) +
    (hasImagery ? 0.01 : 0) +
    (hasFullFootprint ? 0.01 : 0) +
    (hasMultipleSegments ? 0.02 : 0);
  // (c) Pin precision — paneles detectados como proxy de "el pin apunta al techo correcto" — máx +0.03
  const _panelsDetected = panels.length;
  const pinPrecision =
    _panelsDetected >= 10 ? 0.03 :
    _panelsDetected >= 5  ? 0.02 :
    _panelsDetected >= 3  ? 0.01 : 0;
  // (d) Coherence — todas las señales internas alineadas para techo residencial CO — máx +0.04
  const tiltOk = tiltDeg != null && tiltDeg >= 0 && tiltDeg <= 30;
  const azOk = azimuthDeg != null && azimuthDeg >= 120 && azimuthDeg <= 240; // Sur ±60°
  const dataCoherent = hasRealPanels && hasFullFootprint && Array.isArray(roofSegments) && roofSegments.length >= 1;
  const coherence = (tiltOk && azOk && dataCoherent) ? 0.04 : 0;
  let confidence = Math.min(0.99, qualityBase + completeness + pinPrecision + coherence);
  // Cap realista para LOW: por más bonos que sume, imagery 1m/px no puede llegar a 99%
  if (effectiveQuality === 'LOW') confidence = Math.min(confidence, 0.92);
  // Hint de precisión basada en cuántos paneles individuales detectó Google. Si la
  // detección es <5 paneles individuales pero el footprint del edificio es >100 m²,
  // probablemente las coordenadas no apuntan a la construcción correcta.
  const panelsDetected = panels.length;
  const coordinatesPrecisionHint =
    panelsDetected >= 10 ? 'high' :
    panelsDetected >= 3  ? 'medium' : 'low';
  // Google Solar estimate — energía anual + specific yield calculados sobre el modelo
  // 3D del techo (DSM + sunshine quantiles + shade hora a hora). Valores listos para
  // alimentar la cascada de producción en el frontend (Google > PVWatts > PVGIS > PSH).
  const _gPanelW = sp.panelCapacityWatts != null ? Number(sp.panelCapacityWatts) : 250;
  const _gBestPanels = bestEnergyCfg?.panelsCount != null ? Number(bestEnergyCfg.panelsCount) : (best?.panelsCount || null);
  const _gYearKwh = bestEnergyCfg?.yearlyEnergyDcKwh != null ? Number(bestEnergyCfg.yearlyEnergyDcKwh) : null;
  const _gKwpInstalled = (_gBestPanels && _gPanelW) ? (_gBestPanels * _gPanelW / 1000) : null;
  const _gSpecYield = (_gYearKwh && _gKwpInstalled) ? +(_gYearKwh / _gKwpInstalled).toFixed(0) : null;
  const googleSolarEstimate = (_gYearKwh != null) ? {
    yearlyEnergyDcKwh: +_gYearKwh.toFixed(0),
    panelCapacityWatts: _gPanelW,
    bestConfigPanels: _gBestPanels,
    bestConfigKwp: _gKwpInstalled != null ? +_gKwpInstalled.toFixed(2) : null,
    specificYieldKwhPerKwpYear: _gSpecYield,
    panelLifetimeYears: sp.panelLifetimeYears != null ? Number(sp.panelLifetimeYears) : 20,
    peakSunshineHoursYear: sp.maxSunshineHoursPerYear != null ? Number(sp.maxSunshineHoursPerYear) : null,
    panelHeightMeters: sp.panelHeightMeters != null ? Number(sp.panelHeightMeters) : null,
    panelWidthMeters: sp.panelWidthMeters != null ? Number(sp.panelWidthMeters) : null,
    carbonOffsetFactorKgPerMwh: sp.carbonOffsetFactorKgPerMwh != null ? Number(sp.carbonOffsetFactorKgPerMwh) : null,
    source: 'google-solar-api',
    methodology: `DSM + sunshine quantiles ${effectiveQuality}`,
  } : null;

  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2, wholeRoofAreaM2, groundAreaM2,
    maxPanels, panelsDetected, coordinatesPrecisionHint,
    tiltDeg, azimuthDeg,
    sunshineHoursYear: sunshine,
    peakSunshineHoursYear: sp.maxSunshineHoursPerYear != null ? Number(sp.maxSunshineHoursPerYear) : null,
    yearlyEnergyDcKwh: googleSolarEstimate?.yearlyEnergyDcKwh || null,
    panelCapacityWatts: googleSolarEstimate?.panelCapacityWatts || null,
    googleSolarEstimate,
    shadeIndex, shadeSource,
    roofSegments,
    solarPanels,
    panelHeightMeters,
    panelWidthMeters,
    imagery,
    imageryQuality: effectiveQuality,
    staticMapUrl: buildStaticMapUrls(lat, lon, areaM2 || 60).satellite,
    staticMapRoadUrl: buildStaticMapUrls(lat, lon, areaM2 || 60).road,
    staticMapHDUrl: buildStaticMapUrls(lat, lon, areaM2 || 60).satelliteHD,
    source: 'google',
    confidence,
    notes: best ? `config ${best.panelsCount} paneles${shadeIndex != null ? ` · sombra ${Math.round((1 - shadeIndex) * 100)}%` : ''}${effectiveQuality ? ` · calidad ${effectiveQuality}` : ''}${googleSolarEstimate ? ` · ${googleSolarEstimate.specificYieldKwhPerKwpYear} kWh/kWp/año` : ''}` : '',
  } }];
}

// 4) Fallback Claude — estimación por ubicación
if (!AKEY) {
  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2: null, tiltDeg: 10, azimuthDeg: 180,
    shadeIndex: null, shadeSource: null, roofSegments: [], imagery: null,
    source: 'none', confidence: 0,
    notes: 'Solar API sin datos y ANTHROPIC_API_KEY no configurada',
  } }];
}
